var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"이면세계 가변 심도 좌표\\n<color=#ff3636>필하모닉 홀</color>","JPN":"裏世界可変深度座標\\n<color=#ff3636>フィルハーモニーホール</color>","ENG":"[[","TWN":"異界可變深度座標\\n<color=#ff3636>管弦樂廳</color>","THA":"พิกัดความลึกแปรผันในเคาน์เตอร์ไซด์\\n<color=#ff3636>โรงแสดงดนตรีฟิลฮาร์โมนิก</color>","VTN":"Counterside Tọa độ Sâu Có Thể Thay Đổi\\n<color=#ff3636>Phòng Hòa nhạc</color>","SCN":"异界可变深度坐标\\n<color=#ff3636>交响乐厅</color>","DEU":"[[","FRA":"Contremonde, Coordonnées de profondeur variables\\n<color=#ff3636>Hall du Philharmonique</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"구 관리국 야크샤 전대, 카르데나스 전대.\\n강습 작전 수행 중.\\n작전명 <color=#ffd34c>트러블 슈팅</color>","JPN":"旧管理局ヤクシャー戦隊、カルデナス戦隊。\\n強襲作戦遂行中。\\n作戦名<color=#ffd34c>トラブルシューティング</color>","ENG":"[[","TWN":"舊管理局 阿克夏戰隊、卡特納斯戰隊\\n執行強襲作戰中。\\n作戰名稱 <color=#ffd34c>故障排除</color>","THA":"กองพลอักชา กองพลคาร์ดีนาส์ องค์การบริหารโลกในอดีต \\nดำเนินปฏิบัติการจู่โจม\\nชื่อปฏิบัติการ <color=#ffd34c>การแก้ไขปัญหา</color>","VTN":"Cục Quản Lý Cũ Sư đoàn Aksha, Sư đoàn Cardenas.\\nTiến hành Tác chiến Tấn công.\\nTên Tác chiến<color=#ffd34c>Khắc phục sự cố</color>","SCN":"旧管理局夜叉战队、卡尔德纳斯战队。\\n强袭作战执行中。\\n作战代号<color=#ffd34c>故障排除</color>","DEU":"Yaksa- und Cardenas-Division der Alten Administration.\\nAngriffsoperation wird durchgeführt.\\nOperation: <color=#ffd34c>Fehlerbehebung</color>","FRA":"Ancienne Administration - Divisions Yaksha, Cardenas\\nOpération de routine\\nNom de code :<color=#ffd34c>Dépannage d'urgence</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"싫어……! 내 머릿속을 헤집지 마!! 싫어어어어!!","JPN":"やめろ……！　頭ん中を掻きまわすな！！　やめろぉぉぉ！！","ENG":"No...! Get out of my head!! Stop!!","TWN":"走開……！滾出我的腦袋！！討厭！！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"멈춰!! 아군이다! 능력을 사용하지 마!","JPN":"やめろ！！　味方だ！　能力を使うな！","ENG":"Stop!! We’re allies! Don’t use your powers!","TWN":"住手！！是我方人員！不要使用能力！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"틀렸습니다! 이미 제정신이 아니에요! 사살해야 합니다!!","JPN":"だめです！　正気を失っています！　殺さなければ！！","ENG":"Too late! He’s already lost his mind! We must shoot!","TWN":"不行！他現在已經神智不清！必須立刻擊斃！！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"내 배 안에 벌레가 들어 있어…… 내, 내 배 안에서 그게 꿈틀거리다가……!","JPN":"腹の中に虫が入っている……ぼ、僕の腹の中でアレがうごめいて……！","ENG":"There’s a bug in my stomach... It’s, it’s wiggling around in my stomach...!","TWN":"我肚子裡有蟲……蟲在我的肚子裡蠕動……！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"정신 차려, 이 멍청아! 그건 놈들이 덮어 씌운 기억이야! 속지 마!!","JPN":"しっかりしろ、バカ野郎！　それはやつらが上書きした記憶だ！　騙されるな！！","ENG":"Pull yourself together, idiot! That’s just a memory they’ve planted into your brain! Don’t be fooled!","TWN":"傻瓜，你清醒一點！這是那些傢伙植入的記憶！不可以上當！！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"어서 진정제 주사해! 저 놈 자기 손으로 배 가르는 꼴 보고 싶어?!","JPN":"早く鎮静剤を打て！　あいつが自分で腹を切るところを見たいのか！？","ENG":"Somebody, sedate him! Do you want to see him rip his stomach apart with his own hands?!","TWN":"立刻給他打鎮定劑！還是你想看他把自己的肚皮挖破？！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>지휘부에! 멘탈 프린팅을 촉발하는 파동이 검출되었습니다!</color>","JPN":"<color=#ffd34c>司令部へ！　メンタル・プリンティングを起こす波動が検出されました！</color>","ENG":"<color=#ffd34c>Command! A wave triggering Mental Printing has been detected!</color>","TWN":"<color=#ffd34c>指揮部感應到觸發智力複印的波動！</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>첩보가 틀렸습니다! 마에스트로가 아직 이곳에……!</color>","JPN":"<color=#ffd34c>諜報が間違っていました！　マエストロがまだここに……！</color>","ENG":"<color=#ffd34c>Our intel was wrong! Maestra is still here...!</color>","TWN":"<color=#ffd34c>情報有誤！指揮家尚未……！</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"관리국 놈들은 모두 죽여 버려! 안 돼, 쏘지 마! 죽여 버려! 함장님! 사, 살려……!","JPN":"管理局のやつらは全員死んじまえ！　やめろ、撃つな！　殺せ！　艦長！　た、助け……！","ENG":"Kill everyone from the Administration! Wait, don’t shoot! DIE! Leader! Sa-Save M...!","TWN":"把管理局的傢伙全都殺光！不可以，別開槍！殺光！艦長！救我……！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"여기는……. 카르데나스 부전대장, 몽타뉴…….","JPN":"こちら……カルデナス副戦隊長、モンターニュ……","ENG":"This is... Cardenas Deputy Commander Montagne...","TWN":"這裡是……卡特納斯副戰隊長 蒙塔妮……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"현재 아군의 70% 가량이 전투불능 상태…… 작전은 실패다…….","JPN":"現在、味方の70％程度が戦闘不能……作戦は失敗だ……","ENG":"Currently, 70% of our allies are incapacitated... The operation is a failure...","TWN":"目前我方人員中，有70%已經失去作戰能力……作戰失敗……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"차원 도약이 차단되어 생존자들도 퇴각할 수가 없다! 너무 늦기 전에 어서 원군을……!","JPN":"次元跳躍が遮断され、生き残りも退却できない！　遅れる前に早く援軍を……！","ENG":"Dimension jump is being blocked, the survivors can't retreat! Quick, before it's too late—","TWN":"目前次元跳躍關閉中，以至於人員無法撤退！請盡快派遣援軍……！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};